{
  "name": "Low-Income Home Energy Assistance Program (LIHEAP)",
  "eligibility": {
    "age": null,
    "income_limits": "Maximum gross household income for 2025-2026 season (applies to HEAP/LIHEAP in Maine): Household of 1: $3,070 (1 month), $9,209 (3 months), $36,836 (12 months); 2: $4,014/$12,043/$48,170; 3: $4,959/$14,876/$59,504; 4: $5,903/$17,710/$70,839; 5: $6,848/$20,543/$82,173; 6: $7,792/$23,377/$93,507; 7: $7,969/$23,908/$95,632; 8: $8,146/$24,439/$97,757; 9: $8,324/$24,971/$99,882; 10: $8,501/$25,502/$102,008. For >10 persons, contact Community Action Agency (CAA). Paid documented medical expenses may be deducted from income. TANF recipients are automatically income-eligible and receive highest benefit for household size. Household includes everyone at address sharing utility bill. Proof of citizenship or eligible immigration status required (US citizen, refugee, asylee, paroled >=1 year, etc.; mixed status OK for eligible members).",
    "asset_limits": "No asset limits mentioned.",
    "other_requirements": ["Proof of citizenship/immigration status for household members.", "Must face energy costs (homeowners/renters, even if heat in rent)."]
  },
  "benefits": {
    "type": "financial",
    "value": "One-time payment for heating costs directly to utility/fuel provider. Amount based on household size, income, fuel type, and other factors. Crisis component for emergencies (e.g., shutoff, broken heater). Highest benefit for TANF households. Specific max/min amounts not detailed; varies.",
    "varies_by": "household_size|priority_tier"
  },
  "application": {
    "methods": ["Online via MaineHousing portal (starting 2024; exact URL: mainehousing.org/programs-services/energy/energydetails/liheap)", "In-person or phone appointment at local Community Action Agency (CAA; many start July 1; contact CAA directly)", "Phone examples: Community Concepts 800-866-5588; general info 1-800-452-4668 or mainehousing.org"],
    "processing_time": "Not specified; first-come first-served, funds limited.",
    "waitlist": "No waitlist mentioned; apply early as funding may run out and demand up 20%.",
    "forms": ["No specific form name/number; applications via CAA or online."],
    "documents": ["Names, DOB, SSN, proof of citizenship for all household members.", "Unexpired photo ID of applicant.", "Proof of gross income last 30 days/1 month or 12 months (pay stubs, W2, 1099, tax filings, unemployment docs, SS/pension/disability statements, etc.).", "Proof of address (rent receipt, lease, etc.).", "Medical expense docs if deducting."]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available statewide via local CAAs.",
    "regional_variations": "Administered by local Community Action Agencies (CAAs); contact specific CAA for appointments, details. No specific wait time or benefit variations noted by region.",
    "offices_or_providers": ["Local Community Action Agencies (CAAs); e.g., Community Concepts, Inc. (800-866-5588). Full list via mainehousing.org."]
  },
  "official_source": "https://www.mainehousing.org/programs-services/energy/energydetails/liheap",
  "gotchas": ["Funding first-come first-served; apply ASAP, especially fall/winter for heating (not year-round; no cooling).", "Respond immediately to document requests or app incomplete.", "Income gross before taxes; includes all at address on utility bill.", "Medical deductions or TANF can qualify over limits—apply anyway.", "Crisis only for emergencies.", "Immigration status: eligible members only in mixed households."],
  "data_shape_notes": "Income table by time period (1/3/12 months) and household size; medical deductions and TANF auto-qualify; CAA-administered statewide with local contacts; benefits by size/income/fuel."
}

{
  "name": "State Health Insurance Assistance Program (SHIP) - Maine Senior Health Insurance Assistance Program",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; services are free and available regardless of income.[2]",
    "asset_limits": "No asset limits or tests apply.[2]",
    "other_requirements": ["Available to older people (typically Medicare-eligible age 65+), people with Medicare due to disability (under 65), their families, and caregivers.[2][4]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free, confidential one-on-one counseling including: information on Medicare (Parts A, B, C, D), Medicare Advantage, Medigap, MaineCare, prescription drug coverage/options, preventive benefits, medical bills/claims/appeals, comparison of supplemental policies/plans, enrollment in Medicare Savings Programs, referrals to agencies (e.g., CMS, SSA, DHHS), and programs to reduce out-of-pocket costs like prescription discounts. Provided by trained counselors who do not sell insurance.[2][5]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: Contact local providers such as Southern Maine Agency on Aging at 207-396-6524 for appointments (phone, Zoom, in-person at select locations);[8]", "Statewide: Call Maine Office of Aging and Disability Services (no direct number in results, use shiphelp.org for local connection);[3][9]", "In-person or phone through Maine's five Area Agencies on Aging or Legal Services for Maine Elders;[2]", "Website: www.shiphelp.org to connect with local Maine SHIP counselors.[9]"],
    "processing_time": "No formal application or processing; services provided via appointment scheduling, typically immediate upon contact.[2][8]",
    "waitlist": null,
    "forms": ["No specific forms required; counselors assist with any needed enrollment forms during sessions (e.g., Medicare Savings Programs).[2]"],
    "documents": ["No documents needed to start; bring Medicare cards, bills, notices, or insurance details if addressing specific issues.[2]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; covers all of Maine.[3]",
    "regional_variations": "Delivered through a network of five Area Agencies on Aging and local affiliates (e.g., Southern Maine Agency on Aging), with locally focused counseling reflecting regional Medicare options, providers, and resources; appointment availability may vary by local office.[2][7][8]",
    "offices_or_providers": ["Office of Aging and Disability Services, 11 State House Station, 41 Anthony Ave., Augusta, ME 04333;[3]", "Five Area Agencies on Aging statewide;[2]", "Example: Southern Maine Agency on Aging (phone 207-396-6524).[8]"]
  },
  "official_source": "https://www.maine.gov/dhhs/oads/get-support/older-adults-disabilities/older-adult-services/ship-medicare-assistance[2]",
  "gotchas": ["Not an insurance or financial aid program—provides counseling only, no direct payments or coverage;[2]", "Counselors do not sell or recommend specific policies, only objective info—people miss this and expect sales;[2]", "Confused with MaineCare (which has income limits); SHIP helps navigate Medicare/MaineCare but has open eligibility;[1][2]", "Services via local agencies, not centralized—must contact regional provider for appointment.[7][8]"],
  "data_shape_notes": "no income/asset test; counseling-only service via statewide network of Area Agencies on Aging with local delivery variations; open to Medicare beneficiaries/families regardless of income"
}

{
  "name": "Senior Community Service Employment Program (SCSEP)",
  "eligibility": {
    "age": 55,
    "income_limits": "Household income at or below 125% of the federal poverty level. Exact dollar amounts vary annually by household size and are not specified in current sources; families must check current federal poverty guidelines via Maine Department of Labor or CareerCenter for precise figures (e.g., for 2026, consult official FPL tables).[2][5][6]",
    "asset_limits": "No asset limits mentioned in sources.",
    "other_requirements": ["Unemployed", "Looking for work", "Priority given to veterans and qualified spouses of veterans, then individuals over age 65, with disabilities, low literacy skills, limited English proficiency, rural residents, homeless or at risk, low employment prospects, or those who failed to find employment after American Job Center services."[1][2][5][6]]
  },
  "benefits": {
    "type": "employment",
    "value": "Paid, hands-on work experience and training (average 20 hours/week) at nonprofit or public agencies (e.g., schools, hospitals, municipal offices) in high-growth fields like healthcare, office administration, food preparation, customer service; paid at the highest applicable federal, state, or local minimum wage; includes training classes/workshops, CareerCenter employment services, support services for barriers, on-site mentoring, and bridge to unsubsidized employment.[1][3][5][6]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Visit Maine Department of Labor's Work Source Maine Virtual CareerCenter (https://www.myworksourcemaine.gov/resources/senior-community-service-employment-program-scsep-associates-training-development)", "Contact Area Agencies on Aging (AAAs) for information and referral (all five AAAs statewide)", "Attend online orientation workshops via Maine CareerCenter (e.g., https://www.mainecareercenter.com/employment/workshop.shtml?id=6455292)", "Call providers like A4TD at (800) 439-3307 or visit https://www.a4td.org", "Maine DHHS OADS page: https://www.maine.gov/dhhs/oads/get-support/older-adults-disabilities/older-adult-services/scsep"],
    "processing_time": "Not specified in sources.",
    "waitlist": "Limited slots (supports 122 participants statewide at a time); new enrollees enter as others transition to employment.[3]",
    "forms": ["OADS SCSEP Participant Application (available via AAAs or providers).[9]"],
    "documents": "Not explicitly listed; prepare proof of age, unemployment status, income (to verify ≤125% FPL), and veteran status if applicable."
  },
  "geography": {
    "statewide": true,
    "restrictions": "Available statewide; national grant covers remaining 13.5 counties plus part of York County.[1][3]",
    "regional_variations": "Administered via five Area Agencies on Aging (AAAs) providing info/referral and some training; different subgrantees/providers (e.g., A4TD, CWI Works); no specific wait time differences noted, but capacity limited statewide.[2][3]",
    "offices_or_providers": ["Maine CareerCenters statewide", "Five AAAs", "A4TD (https://a4td.org)", "CWI Works (https://www.cwiworks.org)"]
  },
  "official_source": "https://www.maine.gov/dhhs/oads/get-support/older-adults-disabilities/older-adult-services/scsep",
  "gotchas": ["Must be actively looking for unsubsidized employment (not permanent jobs or retirement income)", "Part-time training only (avg. 20 hrs/wk), not full-time work", "Income test is strict at 125% FPL (check current levels as they update yearly)", "Priority tiers may delay entry for non-veterans/under 65", "Limited slots (122 statewide), so transitions create openings but wait possible", "Focus is workforce training bridge, not long-term community service.[3][5][6]"],
  "data_shape_notes": "Statewide with AAA coordination and subgrantees; priority by veteran status then age/disability/rural; slots capped at 122 participants; income at 125% FPL (annual table required); no asset test."
}

{
  "name": "Maine Legal Services for the Elderly",
  "eligibility": {
    "age": 60,
    "income_limits": "Income limits are not explicitly stated in available sources; services target low-income seniors, often those at or below 200% of federal poverty guidelines based on similar Maine legal aid programs, but families should call the helpline for current assessment[2][5][7]. No specific dollar amounts or household size table provided.",
    "asset_limits": "No asset limits specified; focus is on low-income eligibility determined case-by-case[2][5].",
    "other_requirements": ["Maine resident", "Basic human needs at stake (e.g., MaineCare eligibility issues, elder abuse, housing, public benefits)", "Non-criminal legal problems"]
  },
  "benefits": {
    "type": "service",
    "value": "Free legal services including information, advice, and representation on Medicare/MaineCare disputes, health coverage, elder abuse/protection orders, housing/eviction/foreclosure, consumer debt, public assistance benefits, guardianship, discharges, powers of attorney, health care advance directives, and Medicare Part D prescription drug assistance[2][5][9].",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Phone: Helpline at 1-800-750-5353 (in-state) or 207-623-1797[2][5][9]", "Website: mainelse.org for information and Elder Rights Handbook[2][9]", "In-person: Attorneys in offices across the state for representation cases[5]"],
    "processing_time": "Not specified; initial helpline advice is immediate, representation depends on case priority.",
    "waitlist": null,
    "forms": ["No specific application form required; use website resources or call helpline. Avoid pre-printed powers of attorney forms from stores/internet as they may not be legal in Maine[2]"],
    "documents": ["Not explicitly listed; prepare details on legal issue, income proof if relevant, Maine residency verification. Call helpline for guidance[2][5]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available to Maine residents 60+ statewide[2][5][9]",
    "regional_variations": "Attorneys located in offices across the state; funded through Bureau of Elder and Adult Services and Area Agencies on Aging (AAA), which may influence local providers but services consistent[5][6]",
    "offices_or_providers": ["Offices across Maine; specific locations via helpline[5]"]
  },
  "official_source": "https://mainelse.org[9]",
  "gotchas": ["Services are priority-based for basic human needs at stake, not all cases accepted; may refer to private attorneys if unable to help[5]", "Do not use generic pre-printed legal forms (e.g., powers of attorney) as they may be invalid in Maine—consult LSE attorney[2]", "Not a general legal aid; focused on seniors 60+ with specific elder issues, not criminal matters[2][5]", "Nursing homes may push MaineCare applications without asset protection advice—seek LSE for related issues[3]"],
  "data_shape_notes": "No fixed income/asset tables; eligibility case-by-case for low-income seniors with priority on human needs crises; statewide with local offices; distinguishes from general legal aid by elder-specific focus and free helpline advice"
}
